class Solution:
    def numberOfRightTriangles(self, grid: List[List[int]]) -> int:
        rows, cols = len(grid), len(grid[0])
        row_counts = [0] * rows
        col_counts = [0] * cols

        for i in range(rows):
            for j in range(cols):
                if grid[i][j]:
                    row_counts[i] += 1
                    col_counts[j] += 1

        count = 0
        for i in range(rows):
            for j in range(cols):
                if grid[i][j]:
                    count += (row_counts[i] - 1) * (col_counts[j] - 1)

        return count
